using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizer
{
    private static readonly char[] SentenceDelimiters = ['.', '!', '?'];

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(text);
        var scored = sentences
            .Select((s, i) => (Sentence: s, Index: i, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var raw = new List<string>();
        int start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (SentenceDelimiters.Contains(text[i]))
            {
                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                    raw.Add(sentence);
                start = i + 1;
            }
        }

        // Capture any trailing text without terminal punctuation.
        if (start < text.Length)
        {
            var trailing = text[start..].Trim();
            if (trailing.Length > 0)
                raw.Add(trailing);
        }

        return raw;
    }

    private static Dictionary<string, int> ComputeWordFrequencies(string text)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var match in WordRegex().EnumerateMatches(text))
        {
            var word = text.Substring(match.Index, match.Length).ToLowerInvariant();
            if (word.Length <= 2) continue; // skip very short / stop-ish words
            frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
        }
        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> frequencies)
    {
        double score = 0;
        int wordCount = 0;
        foreach (var match in WordRegex().EnumerateMatches(sentence))
        {
            var word = sentence.Substring(match.Index, match.Length).ToLowerInvariant();
            if (frequencies.TryGetValue(word, out int freq))
                score += freq;
            wordCount++;
        }
        return wordCount > 0 ? score / wordCount : 0;
    }

    [GeneratedRegex(@"\b\w+\b")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizer _summarizer;

    public SummarizeController(DocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        var originalWordCount = request.DocumentText.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
        var summaryWordCount = summary.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWordCount,
            SummaryWordCount = summaryWordCount
        });
    }
}

